REQUIRED_FIELDS = ["message_id", "source_object", "target_object", "contour", "role", "payload", "proof_policy"]


def validate_message(message):
    errors = []
    for field in REQUIRED_FIELDS:
        if field not in message:
            errors.append(f"missing field {field}")
    policy = message.get("proof_policy", {}) if isinstance(message, dict) else {}
    if policy.get("contains_secret") is True:
        errors.append("message contains secret")
    if policy.get("claims_release_proof") is True:
        errors.append("message claims release proof")
    if policy.get("template_only") is True and policy.get("claims_release_proof") is True:
        errors.append("template cannot claim release proof")
    return (not errors, errors)


def consume(message):
    ok, errors = validate_message(message)
    return {"ok": ok, "release_pass": False, "errors": errors, "target": message.get("target_object") if isinstance(message, dict) else None}


def main():
    sample = {"message_id":"sample","source_object":"operator","target_object":"GD","contour":"C1","role":"general_director","payload":{"text":"local"},"proof_policy":{"contains_secret":False,"template_only":False,"claims_release_proof":False}}
    result = consume(sample)
    print(json.dumps(result, ensure_ascii=False))
    return result

if __name__ == "__main__":
    main()
