ALLOWED = {
    "queued": ["analyst_proposal"],
    "analyst_proposal": ["auditor_precheck"],
    "auditor_precheck": ["worker_execution"],
    "worker_execution": ["auditor_postcheck"],
    "auditor_postcheck": ["completed"],
}


def advance(state, next_state, proof=None):
    current = state.get("state") if isinstance(state, dict) else None
    if next_state not in ALLOWED.get(current, []):
        return {"ok": False, "release_pass": False, "error": f"invalid transition {current}->{next_state}"}
    if next_state == "completed" and not proof:
        return {"ok": False, "release_pass": False, "error": "completed requires proof"}
    return {"ok": True, "release_pass": False, "state": next_state, "proof": proof}


def main():
    result = advance({"state":"queued"}, "analyst_proposal")
    print(json.dumps(result, ensure_ascii=False))
    return result

if __name__ == "__main__":
    main()
